// Validate required fields
const body = $input.first().json.body || $input.first().json;

const required = ['aiName', 'whatsappNumber', 'tone', 'style', 'goal'];
const missing = required.filter(f => !body[f] || String(body[f]).trim() === '');

if (missing.length > 0) {
  return [{
    json: {
      valid: false,
      success: false,
      error: `Campos obrigatórios faltando: ${missing.join(', ')}`
    }
  }];
}

// Pass validated data forward
return [{
  json: {
    valid: true,
    aiName: String(body.aiName).trim(),
    whatsappNumber: String(body.whatsappNumber).replace(/\D/g, ''),
    tone: String(body.tone).trim(),
    style: String(body.style).trim(),
    behavior: String(body.behavior || 'objetivo').trim(),
    businessContext: String(body.businessContext || '').trim(),
    goal: String(body.goal).trim(),
    faq: Array.isArray(body.faq) ? body.faq : [],
    plan: String(body.plan || 'Starter').trim()
  }
}];

// Store user config in workflow static data
const data = $input.first().json;
const phone = data.whatsappNumber;
const userId = 'usr_' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6);

// Get persistent storage
const staticData = $getWorkflowStaticData('global');
if (!staticData.users) {
  staticData.users = {};
}

// Check if user already exists (update vs create)
const isUpdate = !!staticData.users[phone];
const existingUserId = isUpdate ? staticData.users[phone].userId : userId;

// Store/update user configuration
staticData.users[phone] = {
  userId: existingUserId,
  aiName: data.aiName,
  tone: data.tone,
  style: data.style,
  behavior: data.behavior,
  businessContext: data.businessContext,
  goal: data.goal,
  faq: data.faq,
  plan: data.plan,
  whatsappNumber: phone,
  createdAt: isUpdate ? staticData.users[phone].createdAt : new Date().toISOString(),
  updatedAt: new Date().toISOString(),
  active: true
};

return [{
  json: {
    success: true,
    userId: existingUserId,
    phone: phone,
    isUpdate: isUpdate,
    message: isUpdate ? 'Configuração atualizada com sucesso' : 'IA configurada com sucesso'
  }
}];

